import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useProducts } from './ProductContext';
import { ShoppingBag, LogOut, Package, BarChart2, History, ShieldCheck, Search, Plus } from 'lucide-react';

const Products = () => {
  const navigate = useNavigate();
  const { products, user, logout } = useProducts();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans">
      <nav className="fixed w-full top-0 z-50 bg-white border-b border-gray-100 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-8 h-full">
            <NavLink to="/products" active><Package className="w-5 h-5" /><span>Mahsulotlar</span></NavLink>
            <NavLink to="/sales"><BarChart2 className="w-5 h-5" /><span>Savdo</span></NavLink>
            <NavLink to="/history"><History className="w-5 h-5" /><span>Tarix</span></NavLink>

            {/* Faqat Admin uchun Admin tugmasi */}
            {user?.role === 'admin' && (
              <NavLink to="/admin"><ShieldCheck className="w-5 h-5" /><span>Admin</span></NavLink>
            )}
          </div>
          <button 
            onClick={handleLogout} 
            className="flex items-center gap-2 text-gray-500 hover:text-red-600 font-semibold transition-colors py-2 px-4 rounded-xl hover:bg-red-50"
          >
            <LogOut className="w-5 h-5" /> Chiqish
          </button>
        </div>
      </nav>

      <main className="pt-32 pb-20 px-6 max-w-7xl mx-auto">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10">
          <div>
            <h1 className="text-3xl font-bold text-gray-900">Mahsulotlar</h1>
            <p className="text-gray-500 mt-1">
              Xush kelibsiz, <span className="font-bold text-purple-700">{user?.email}</span> ({user?.role})
            </p>
          </div>
          <Link 
            to="/add-product" 
            className="bg-purple-700 text-white px-6 py-3 rounded-2xl font-bold flex items-center gap-2 hover:bg-purple-800 shadow-lg active:scale-95 transition-all"
          >
            <Plus className="w-6 h-6" /> Yangi qo'shish
          </Link>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {products.map((product) => (
            <Link 
              key={product.id} 
              to={`/product/${product.id}`} 
              className="bg-white rounded-[2.5rem] p-4 shadow-md hover:shadow-xl transition-all border border-gray-50 group block"
            >
              <div className="aspect-[4/3] rounded-[2rem] overflow-hidden mb-6">
                <img src={product.image} alt={product.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" />
              </div>
              <div className="px-2 pb-2">
                <h3 className="text-xl font-bold text-gray-900 mb-3">{product.name}</h3>
                <div className="flex items-center justify-between">
                  <span className="text-2xl font-black text-purple-700">{product.price.toLocaleString()} <span className="text-sm font-bold">so'm</span></span>
                  <div className="bg-slate-100 px-4 py-2 rounded-2xl text-slate-600 text-sm font-bold">Omborda: {product.stock}</div>
                </div>
              </div>
            </Link>
          ))}
        </div>
      </main>
    </div>
  );
};

const NavLink = ({ to, children, active = false }) => (
  <Link to={to} className={`flex items-center gap-2 px-1 h-full font-bold transition-all relative ${active ? 'text-purple-700' : 'text-gray-500 hover:text-purple-600'}`}>
    {children}
    {active && <div className="absolute bottom-0 left-0 right-0 h-1 bg-purple-700 rounded-t-full"></div>}
  </Link>
);

export default Products;
